    bool isPossible(vector<int>& nums) {
        unordered_map<int, int> count, need;
        for (int x : nums) {
            if (need.count(x - 1)) {
                need[x - 1]--;
                need[x] = need[x] + 1;
            } else {
                if (count[x] < 2) return false;
                count[x - 1] = count[x - 1] - 2;
                need[x] = need[x] + 1;
            }
            count[x]--;
        }
        for (int x : nums) {
            if (need[x] > 0) return false;
        }
        return true;
    }
};
